import 'dart:convert';

import '../models/work_project.dart';

class WorkProjectProvider {
  List<WorkProject> getWorkProjects() {
    final decoded = json.decode(_json);
    final casted = (decoded as List).cast<Map<String, dynamic>>();
    final parsed = casted.map(WorkProject.fromMap).toList();

    parsed.sort((a, b) => b.period.compareTo(a.period));

    return parsed;
  }
}

